     * back to `https://blossom.primal.net`.
     */
    func blossomUpload(data: Data, contentType: String, serverUrl: String?) async throws  -> String
    
    func currentPubkey()  -> String?
    
    func loginNsec(secret: String) throws  -> String
    
    func loginPubkey(npubOrHex: String) throws  -> String
    
    func logout() 
    
