public enum CommentAnchor {
    
    case episode(guid: String
    )
    case clip(uuid: String
    )
}


#if compiler(>=6)
extension CommentAnchor: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeCommentAnchor: FfiConverterRustBuffer {
    typealias SwiftType = CommentAnchor

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> CommentAnchor {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .episode(guid: try FfiConverterString.read(from: &buf)
        )
        
        case 2: return .clip(uuid: try FfiConverterString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: CommentAnchor, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .episode(guid):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(guid, into: &buf)
            
        
        case let .clip(uuid):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(uuid, into: &buf)
            
        }
    }
}


