public enum DataChangeType {
    
    /**
     * kind:0 profile metadata arrived for `pubkey`.
     */
    case profileUpdated(pubkey: String, profile: ProfileRecord
    )
    /**
     * A NIP-22 (kind:1111) comment arrived for the open subscription.
     */
    case commentReceived(comment: CommentRecord
    )
    /**
     * A NIP-10 thread event arrived.
     */
    case threadEventReceived(event: ThreadEventRecord
    )
    /**
     * NIP-74 podcast show announcement (kind:30074).
     */
    case podcastShowDiscovered(show: PodcastShowRecord
    )
    /**
     * NIP-74 podcast episode announcement (kind:30075).
     */
    case podcastEpisodeDiscovered(episode: PodcastEpisodeRecord
    )
    /**
     * A peer-to-peer agent message arrived (kind:1 with `#p` tag).
     */
    case peerMessageReceived(message: PeerMessageRecord
    )
    /**
     * Note author metadata (display name + picture) resolved.
     */
    case noteAuthorResolved(pubkey: String, author: NoteAuthorRecord
    )
    /**
     * NIP-46 signer connected.
     */
    case signerConnected(pubkey: String
    )
    /**
     * NIP-46 signer disconnected / errored.
     */
    case signerDisconnected(reason: String
    )
    /**
     * A relay in the pool changed connection state.
     */
    case relayStatusChanged(url: String, state: RelayStatus
    )
    /**
     * End-of-stored-events signal for the subscription.
     */
    case subscriptionEose
}


